"""Plate buckling result dataclasses."""

from dataclasses import dataclass
from typing import Optional


@dataclass
class stress_state:
    """
    Stores the stress state of a plate for buckling assessment.
    Based on EN 1993-1-5:2006, Chapter 4.

    Args:
        sigma_1: stress at the initial edge in MPa (float). Compression is positive.
        sigma_2: stress at the end edge in MPa (float). Compression is positive.
        class_plate: plate class according to EN 1993-1-1 (1, 2, 3 or 4)
        bc: compression zone width (mm)
        bt: tension zone width (mm)
        bc_initial_edge: True -> compression zone is at the initial edge, False -> compression zone is at the end edge
    """

    # Edge stresses (MPa). Compression is positive. sigma_1 is the larger edge stress
    sigma_1: float
    sigma_2: float

    # Plate class according to EN 1993-1-1 (1, 2, 3 or 4)
    class_plate: int

    # Compression and tension zone widths (mm)
    bc: Optional[float] = None
    bt: Optional[float] = None
    bc_initial_edge: Optional[bool] = (
        None  # True -> compression zone is at the initial edge, False -> compression zone is at the end edge
    )

    @property
    def psi(self) -> float:
        """Stress ratio sigma_2 / sigma_1."""
        if self.sigma_1 == 0:
            return -1e10
        return self.sigma_2 / self.sigma_1

    def summary(self) -> str:
        """Returns a formatted string with the stress state."""
        return (
            f"--- Plate Stress State ---\n"
            f"Edge Stress sigma_1: {self.sigma_1:.2f} MPa\n"
            f"Edge Stress sigma_2: {self.sigma_2:.2f} MPa\n"
            f"Stress Ratio (psi): {self.psi:.3f}\n"
            f"Plate Class: {self.class_plate}"
        )


@dataclass
class LocalBucklingResults:
    """
    Stores plate buckling calculation results for unstiffened elements.
    Based on EN 1993-1-5:2006, Chapter 4.4.

    args:
        k_sigma: buckling factor from Table 4.1 (internal) or Table 4.2 (outstand)
        lambda_p: relative plate slenderness (Eq. 4.3)
        sigma_cr: elastic critical plate buckling stress (MPa)
        rho: reduction factor for plate buckling (Eq. 4.2 internal, Eq. 4.3 outstand)
        beff: total effective width (mm)
        be1: effective width portions near sigma_1  (internal elements only)
        be2: effective width portions near sigma_2  (internal elements only)
        epsilon: material factor sqrt(235/fy)
    """

    # Buckling factor from Table 4.1 (internal) or Table 4.2 (outstand)
    k_sigma: Optional[float] = None

    # Relative plate slenderness (Eq. 4.3)
    lambda_p: Optional[float] = None

    # Elastic critical plate buckling stress (MPa)
    sigma_cr: Optional[float] = None

    # Reduction factor for plate buckling (Eq. 4.2 internal, Eq. 4.3 outstand)
    rho: Optional[float] = None

    # Total effective width (mm)
    beff: Optional[float] = None

    # Effective width portions near sigma_1 and sigma_2 (internal elements only)
    be1: Optional[float] = None  # near sigma1
    be2: Optional[float] = None

    # Material factor sqrt(235/fy)
    epsilon: Optional[float] = None

    def summary(self) -> str:
        """Returns a formatted string with the buckling status."""
        status = "Fully effective" if (self.rho or 1.0) >= 1.0 else "Buckling governs"
        lines = [
            "--- Plate Buckling Results ---",
            f"Buckling Factor (k_sigma): {self.k_sigma:.3f}" if self.k_sigma else None,
            f"Slenderness (lambda_p): {self.lambda_p:.3f}" if self.lambda_p else None,
            f"Reduction Factor (rho): {self.rho:.3f} -> {status}" if self.rho else None,
            f"Effective Width (beff): {self.beff:.2f} mm" if self.beff else None,
        ]
        return "\n".join(line for line in lines if line is not None)
